draw((-0.5,0)--(6.5,0));
draw((0,-3)--(0,3));
filldraw(Circle((0,0),0.1),white,red);

label("Re", (6.5,0), NE);
label("Im", (0,3), NE);
dot("$3$", (3,0), N);
[/asy]

